// Merge articles page and sitemap data to extract article URLs
const articlesData = $input.all();

// Get both node outputs (articles page and sitemap)
let articleUrls = [];
const seen = new Set();

for (const item of articlesData) {
  const data = item.json;

  // Extract from links array if present (Firecrawl articles page)
  if (data.data && data.data.links && Array.isArray(data.data.links)) {
    for (const link of data.data.links) {
      const url = typeof link === 'string' ? link : link.href || link.url || '';
      if (url && url.includes('thmanyah.com') && !seen.has(url)) {
        // Filter for article-like URLs
        if (/\/articles?\/|\/(ar|en)\/|podcast|episode/i.test(url) ||
            (url.split('/').length >= 5 && !url.includes('#') && !url.endsWith('.xml'))) {
          seen.add(url);
          articleUrls.push(url);
        }
      }
    }
  }

  // Extract from markdown (look for href patterns)
  if (data.data && data.data.markdown) {
    const md = data.data.markdown;
    const linkRegex = /\[([^\]]+)\]\((https?:\/\/[^)]+)\)/g;
    let match;
    while ((match = linkRegex.exec(md)) !== null) {
      const url = match[2];
      if (url && url.includes('thmanyah.com') && !seen.has(url)) {
        seen.add(url);
        articleUrls.push(url);
      }
    }
  }

  // Extract from rawHtml (sitemap URLs)
  if (data.data && data.data.rawHtml) {
    const html = data.data.rawHtml;
    const locRegex = /<loc>([^<]+)<\/loc>/g;
    let match;
    while ((match = locRegex.exec(html)) !== null) {
      const url = match[1].trim();
      if (url && url.includes('thmanyah.com') && !seen.has(url)) {
        if (!url.endsWith('/') || url.split('/').length > 4) {
          seen.add(url);
          articleUrls.push(url);
        }
      }
    }
  }
}

// Deduplicate and limit to 15 most recent/interesting
// Sort: prefer article/episode paths
articleUrls = articleUrls
  .filter(u => !u.includes('sitemap') && !u.includes('.xml') && !u.includes('/tag/') && !u.includes('/page/'))
  .slice(0, 15);

// If we got nothing useful, fallback to known patterns
if (articleUrls.length === 0) {
  articleUrls = [
    'https://thmanyah.com/articles',
    'https://thmanyah.com/podcasts'
  ];
}

return articleUrls.map(url => ({ json: { url } }));

