  analysis = {
    trending_topics: ['general', 'podcasts'],
    writing_style_analysis: 'Unable to parse analysis',
    hook_patterns: [],
    content_gaps: [],
    top_articles: [],
    overall_strategy: 'Analysis parsing failed',
    recommendations_for_ziyada: []
  };
}

const now = new Date().toISOString();
const records = [];

// Create one intel record per top article
const topArticles = analysis.top_articles || [];
if (topArticles.length === 0) {
  // Fallback: create one record with overall website data
  topArticles.push({ title: 'Thmanyah Website Scan', url: 'https://thmanyah.com', topic: 'general', engagement_notes: '' });
}

for (const article of topArticles.slice(0, 10)) {
